sql:
SELECT u.*
FROM users u
INNER JOIN model_deployments md ON u.user_id = md.deployed_by;

SELECT DISTINCT users.user_name
FROM users
JOIN audio_files ON users.user_id = audio_files.user_id;

SELECT audio_files.*, audio_features.*
FROM audio_files
JOIN audio_features ON audio_files.audio_id = audio_features.audio_id;

SELECT audio_files.file_name, users.user_name
FROM audio_files
JOIN users ON audio_files.user_id = users.user_id;

SELECT af.audio_id, af.file_name, af.duration, l.class_name
FROM audio_files af
INNER JOIN labels l ON af.audio_id = l.audio_id;

SELECT model_id, COUNT(*) AS total_features 
FROM audio_features 
GROUP BY model_id;

external_knowledge:
-basic information refers to the audio_id, file_name, file_path, file_size, and upload_date; 
-labeled means associated with at least one label; 
-not yet deployed means having no records in the model_deployments table.

sql:
SELECT AVG(confidence_score) AS average_confidence_score
FROM labels
WHERE class_name = 'children_playing';

SELECT af.file_name, u.user_name
FROM audio_files af
JOIN users u ON af.user_id = u.user_id;

SELECT file_name, file_size
FROM audio_files
WHERE file_size > (
    SELECT AVG(file_size)
    FROM audio_files
);
